---@class LFDTUnitData
local LFDTUnitData = LxClass("LFDTUnitData")

function LFDTUnitData:LFDTUnitData()
    ---@type number UnitView类型枚举 LFastDTUnitViewConst
    self._type = nil

    ---@type boolean 初始化完成
    self._initOk = false

    self._modelScale = Vector3.one

    ---@type number 资源枚举 LFastDTResConst
    self._resType = nil

    ---@type string 资源名字
    self._resName = nil

    self._gridKey = ""

    --- 资源大小
    self._resSize = 1

    ---@type Vector3 localPosition
    self._resSite = Vector3.zero

    ---@type Vector3 position
    self._resPos = Vector3.zero

    ---@type StructDreamTripGrid
    self._gridData = nil

    self._spineType = LDisplaySpine.TYPE_MODEL

    ---@type StructDreamTripEventInfo
    self._curEventInfo = nil

    ---@type boolean 是否战斗事件
    self._isBattle = false
end

--- themeCfg DreamTripMapRef
function LFDTUnitData:SetPlayerData(themeCfg,curPos)
    self._initOk = false

    if not themeCfg then return end

    self._type = LFastDTUnitViewConst.PLAYER

    --- LFastDTPlayerResConst
    local leadingType = tonumber(themeCfg.leadingType)

    local leading = themeCfg.leading
    if leadingType == LFastDTPlayerResConst.MYSELFROLE then
        local figure = gModelPlayer:GetPlayerFigure()
        if figure and figure > 0 then
            local ref = gModelPlayer:GetRoleAdventureImage(figure)
            if ref and not string.isempty(ref.spine) then
                leading = ref.spine
            end
        end
    end

    local resType
    if leadingType == LFastDTPlayerResConst.PIC then
        resType = LFastDTResConst.PIC
    else
        resType = LFastDTResConst.SPINE
    end
    self._resType = resType

    self._resName = leading

    local endPlatform = themeCfg.endPlatform
    curPos.z = endPlatform
    self._resPos = curPos
    self._gridKey = -1
    self._initOk = true
end

--- data  为自定义数据
function LFDTUnitData:SetTargetData(data)
    self._initOk = false
    if not data then return end

    self._type = LFastDTUnitViewConst.TARGET
    self._gridKey = data.key
    self._resType = data.resType
    self._resName = data.resName
    self._resPos = data.curPos
    self._initOk = true
end

---@param grid StructDreamTripGrid
function LFDTUnitData:SetData(grid,_type)
    self._initOk = false

    self._curEventInfo = nil
    self._gridData = grid
    self._type = _type
    self:DisposeGridData()
end

function LFDTUnitData:DisposeGridData()
    local gridData = self:GetGridData()
    if not gridData then return end

    ---@type table<StructDreamTripEventInfo>
    local eventList = gridData.eventList or {}
    if #eventList < 1 then return end

    ---@type StructDreamTripEventInfo
    local showEventInfo
    ---@param v StructDreamTripEventInfo
    for i,v in ipairs(eventList) do
        if not v:CheckIsFinishEvent() then
            showEventInfo = v
            break
        end
    end
    if not showEventInfo then return end

    local eventRefId = showEventInfo.eventRefId
    local eventRef = gModelFastDreamTrip:GetDreamTripEventRefByRefId(eventRefId)
    if not eventRef then return end

    self._curEventInfo = showEventInfo

    self._isBattle = ModelFastDreamTrip.BATTLE_EVENT_ENUM[showEventInfo.eventType]

    self._resType = eventRef.resType
    self._resName = eventRef.res
    self._resSize = tonumber(eventRef.resSize)

    local localPos = Vector3.zero
    local resSite = eventRef.resSite
    if not string.isempty(resSite) then
        local resSiteInfo = string.split(resSite,";")
        local x = tonumber(resSiteInfo[1]) or 0
        local y = tonumber(resSiteInfo[2]) or 0
        local z = tonumber(resSiteInfo[3])
        if not z then z = showEventInfo.index end
        local temp = 100
        localPos = Vector3(x / temp,y / temp,z / temp)
    end
    self._resSite = localPos

    self._gridKey = gridData.index

    self._initOk = true
end

---@return StructDreamTripGrid
function LFDTUnitData:GetGridData()
    return self._gridData
end

function LFDTUnitData:CheckGridFinish()
    if not self._gridData then return true end
    return self._gridData:CheckGridIsFinish()
end

function LFDTUnitData:CheckUnitShowState()
    if self:IsNPCUnit() then
        return not self:CheckGridFinish()
    end
    return true
end

function LFDTUnitData:GetKey()
    return self._gridKey
end

---@return LFastDTResConst
function LFDTUnitData:GetResType()
    return self._resType
end

function LFDTUnitData:GetResName()
    return self._resName
end

---@return Vector3 返回 localPosition 位置
function LFDTUnitData:GetResSite()
    return self._resSite
end

---@return Vector3 返回 position 位置
function LFDTUnitData:GetResPos()
    local resPos = self._resPos
    return Vector3(resPos.x,resPos.y,resPos.z)
end

function LFDTUnitData:GetShowPos(trans)
    if not trans then return end
    if self._type == LFastDTUnitViewConst.NPC then
        trans.localPosition = self:GetResSite()
    else
        trans.localPosition = self:GetResPos()
    end
end

function LFDTUnitData:GetResPosZ()
    local pos = self:IsNPCUnit() and self:GetResSite() or self:GetResPos()
    return pos.z
end

function LFDTUnitData:IsNPCUnit()
    return self._type == LFastDTUnitViewConst.NPC
end

---@return Vector3 返回大小
function LFDTUnitData:GetResSize()
    return self._resSize
end

function LFDTUnitData:GerResSizeVec3()
    local resSize = self._resSize
    return Vector3(resSize,resSize,resSize)
end

---@return StructDreamTripEventInfo
function LFDTUnitData:GetCurEventInfo()
    return self._curEventInfo
end

function LFDTUnitData:UpdateGridData()
    if not self._gridData then return end
    ---@type StructDreamTripGrid
    local gridData = self._gridData
    local newGridData = gModelFastDreamTrip:GetDreamTripGridByIndex(gridData.index)
    if not newGridData then return end
    self._gridData = newGridData
end

function LFDTUnitData:GetUnitViewIndex()
    if not self._gridData then return end
    return self._gridData.index
end

return LFDTUnitData